public class BindingException: UniffiException {
    BindingException() : base() {}
    BindingException(String @Message) : base(@Message) {}

    // Each variant is a nested class


    public class Operation : BindingException {
        // Members
        public string @code;
        public string @message;

        // Constructor
        public Operation(
                string @code,
                string @message) : base(
                "@code" + "=" + @code+ ", " +
                "@message" + "=" + @message) {

            this.@code = @code;

            this.@message = @message;
        }
    }



}

class FfiConverterTypeBindingError : FfiConverterRustBuffer<BindingException>, CallStatusErrorHandler<BindingException> {
    public static FfiConverterTypeBindingError INSTANCE = new FfiConverterTypeBindingError();

    public override BindingException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new BindingException.Operation(
                    FfiConverterString.INSTANCE.Read(stream),
                    FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeBindingError.Read()", value));
        }
    }

    public override int AllocationSize(BindingException value) {
        switch (value) {

            case BindingException.Operation variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@code)
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@message);
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeBindingError.AllocationSize()", value));
        }
    }

    public override void Write(BindingException value, BigEndianStream stream) {
        switch (value) {
            case BindingException.Operation variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.@code, stream);
                FfiConverterString.INSTANCE.Write(variant_value.@message, stream);
                break;
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeBindingError.Write()", value));
        }
    }
}





